import React from "react";
import Marquee from "react-fast-marquee";

import { ProjectsList } from "../utils/ProjectsList";

import "../styles/Projects.css";

function Projects() {
  return (
    <div className="projects-container" data-aos="fade-up">
      <Marquee
        speed={120}
        gradientColor={[3, 0, 46]}
        gradientWidth={100}
        pauseOnHover
        data-aos="fade-up"
      >
        {ProjectsList.map((data, i) => {
          return (
            <div className="projects-marquee-item" key={i}>
              <img
                className="projects-marquee-img"
                src={data.icon}
                alt="marquee-item"
              />
              <h1 className="projects-marquee-text">{data.marqueeName}</h1>
            </div>
          );
        })}
      </Marquee>

      <div className="projects-contents">
        {ProjectsList.map((data, i) => {
          return (
            <div className="projects-item" data-aos="fade-up" key={i}>
              <h1>{data.name}</h1>
              <p>{data.description}</p>
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default Projects;
